prompt --application/shared_components/user_interface/lovs/lista_declaratorias_para_contratos
begin
wwv_flow_api.create_list_of_values(
 p_id=>wwv_flow_api.id(250900431712380856)
,p_lov_name=>'LISTA_DECLARATORIAS_PARA_CONTRATOS'
,p_lov_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    dt.id_declaratoria,',
'    dt.id_declaratoria || '': '' || UPPER(e.nombre_comercial) || '' - '' || UPPER(td.nombre_tipodt) AS TIPO_DECLARATORIA',
'FROM declaratoria_turistica dt',
'    INNER JOIN empresa e ',
'        ON dt.id_empresa = e.id_empresa',
'    INNER JOIN tipo_declaratoria td ',
'        ON dt.id_tipodt = td.id_tipodt',
'WHERE dt.id_usuario = PKG_USUARIOS.f_consulta_usuario(:APP_USER) AND td.permite_ct = ''Y'' AND dt.estadodt = 6',
'ORDER BY dt.id_declaratoria DESC;'))
,p_source_type=>'SQL'
,p_location=>'LOCAL'
,p_return_column_name=>'ID_DECLARATORIA'
,p_display_column_name=>'TIPO_DECLARATORIA'
,p_group_sort_direction=>'ASC'
,p_default_sort_column_name=>'ID_DECLARATORIA'
,p_default_sort_direction=>'DESC_NULLS_FIRST'
);
end;
/
