,p_process_name=>'PRC_INSERTAR_USUARIO'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    vMensaje_Retorno VARCHAR2(355);',
'    vRetorno boolean;',
'',
'begin',
'   if :P4_CEDULA is not null',
'    then',
'        PKG_USUARIOS.sp_insertar_usuario(:P4_NOMBRE, ',
'                                         :P4_PAPELLIDO, ',
'                                         :P4_SAPELLIDO, ',
'                                         :P4_TIPO_CEDULA, ',
'                                         :P4_CEDULA, ',
'                                         :P4_CORREO,',
'                                         :P4_TELEFONO, ',
'                                         :P4_CEDULA, ',
'                                         vMensaje_Retorno, ',
'                                         vRetorno);',
'    end if;',
'    ',
'    if :P4_EXTRANJERO is not null',
'    then',
'        PKG_USUARIOS.sp_insertar_usuario(:P4_NOMBRE, ',
'                                         :P4_PAPELLIDO, ',
'                                         :P4_SAPELLIDO, ',
'                                         :P4_TIPO_CEDULA, ',
'                                         :P4_EXTRANJERO, ',
'                                         :P4_CORREO,',
'                                         :P4_TELEFONO, ',
'                                         :P4_EXTRANJERO, ',
'                                         vMensaje_Retorno, ',
'                                         vRetorno);',
'    end if;',
' ',
'   if vMensaje_Retorno is not NULL-- and vRetorno = true',
'         then',
'             :P4_RESPUESTA := vMensaje_Retorno;',
'             else',
'             :P4_RESPUESTA := vMensaje_Retorno;',
'         end if;',
'         ',
'end;'))
,p_process_error_message=>'Error al registrar el usuario'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(40478391812483210)
