wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(40481137593483238)
,p_process_sequence=>60
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>unistr('PRC_ACTUALIZAR_CONTRASE\00D1A')
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
unistr('    -- Variables para capturar los par\00E1metros IN OUT de la funci\00F3n'),
'    v_codigo_error   VARCHAR2(4000) := NULL; ',
'    v_mensaje_func   VARCHAR2(4000) := NULL; ',
'    v_resultado      NUMBER;',
'    ',
unistr('    -- Constantes para el valor de retorno de la funci\00F3n'),
'    c_success        CONSTANT NUMBER := 1;',
'    c_failure        CONSTANT NUMBER := 0;',
'    ',
'    -- Variables para el control de flujo',
'    v_msg_usuario    VARCHAR2(4000);',
'BEGIN',
'    -- 1. Validar la coincidencia de claves localmente',
'    IF :P5_CLAVE_NUEVA = :P5_CLAVE_CONFIRMAR THEN',
'        ',
unistr('        -- Inicializar los par\00E1metros IN OUT antes de la llamada'),
'        v_codigo_error := NULL; ',
'        v_mensaje_func := NULL;',
'        ',
unistr('        -- 2. Invocar la funci\00F3n f_valida_clave'),
'        v_resultado := PKG_USUARIOS.f_valida_clave(',
'            param_usuario        => :P5_ID_USUARIO, ',
'            param_clave          => :P5_CLAVE_NUEVA, ',
'            paramCodigoError     => v_codigo_error, ',
'            param_mensaje        => v_mensaje_func ',
'        );',
'        ',
unistr('        -- 3. Manejo del Resultado de la Funci\00F3n'),
'        IF v_resultado = c_failure THEN',
unistr('            -- **FALLO EN LA VALIDACI\00D3N DE LA FUNCI\00D3N (0: Formato, Historial, etc.)**'),
'            ',
unistr('            -- Mostrar el mensaje de error devuelto por la funci\00F3n y detener el submit'),
'            APEX_ERROR.ADD_ERROR (',
unistr('                p_message          => ''Validaci\00F3n de Clave Fallida: ['' || NVL(v_codigo_error, ''??'') || ''] '' || NVL(v_mensaje_func, ''Error de validaci\00F3n desconocido.''),'),
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'',
'        ELSIF v_resultado = c_success THEN',
unistr('            -- **\00C9XITO EN LA FUNCI\00D3N (1: Clave V\00E1lida)**'),
'            ',
'            v_msg_usuario := NVL(v_mensaje_func, ''Cambio de Clave Exitoso.'');',
'            ',
'            -- Revisamos si el mensaje devuelto indica que el cambio *no* se hizo por inactividad.',
'            IF v_msg_usuario LIKE ''%INACTIVO%'' THEN',
unistr('                -- Si es una validaci\00F3n exitosa, pero no se hizo el cambio (usuario Inactivo)'),
unistr('                -- Mostramos un mensaje de ERROR (rojo) para notificar que la acci\00F3n fall\00F3.'),
'                APEX_ERROR.ADD_ERROR (',
'                    p_message          => v_msg_usuario,',
'                    p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'                );',
'            ELSE',
unistr('                -- Si es un \00E9xito real (clave cambiada)'),
unistr('                -- Usamos la variable global compatible con APEX 22.x para el \00E9xito (verde).'),
'                APEX_APPLICATION.G_PRINT_SUCCESS_MESSAGE := v_msg_usuario;',
'            END IF;',
'',
'        END IF;',
'',
'    ELSE',
'        -- **FALLO EN LA COINCIDENCIA DE CLAVES**',
'        APEX_ERROR.ADD_ERROR (',
'            p_message          => ''Error: Las claves ingresadas no coinciden. Verifique por favor.'',',
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
'    END IF;',
'    ',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        APEX_ERROR.ADD_ERROR (',
unistr('            p_message          => ''Error Cr\00EDtico Inesperado: '' || SQLCODE || '' - '' || SQLERRM,'),
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
'END;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(41039528762478459)
);
