wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(247522210692690409)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_INSERTAR_EMPRESA_FISISCA'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    vcedula             VARCHAR2(30);',
unistr('    v_resultado_funcion VARCHAR2(4000); -- \00A1Ahora captura el VARCHAR2 de retorno!'),
'    v_codigo_estado     NUMBER;',
'    v_mensaje           VARCHAR2(4000);',
'    v_temp_id_empresa   NUMBER; -- Variable temporal para extraer el ID',
'',
'begin',
'',
unistr('    -- 1. Identificar la c\00E9dula del usuario logueado'),
'    vcedula := PKG_USUARIOS.f_consulta_usuario(:APP_USER);',
'',
unistr('    -- 2. Ejecutar la inserci\00F3n de la empresa (capturando el resultado completo)'),
'    if :P6_TIPO_IDENTIFICACION = ''NACIONAL'' then',
'        ',
'        v_resultado_funcion := PKG_EMPRESA.f_insertar_empresa(',
'                                    :P6_ID_PROVINCIA, ',
'                                    :P6_NOMBRE, -- pNOMBRE_SOLICITANTE',
unistr('                                    :P6_CEDULA_NACIONAL, -- C\00E9dula Nacional (pCEDULA)'),
'                                    :P6_TELEFONO, ',
'                                    :P6_CORREO,',
'                                    :P6_DIRECCION_EXACTA, ',
'                                    :P6_ID_CANTON, ',
'                                    :P6_ID_DISTRITO, ',
'                                    ''FISICA'', -- pTIPO_CEDULA',
'                                    :P6_TIPO_IDENTIFICACION, -- pNACIONAL',
'                                    NULL, -- pRAZON_SOCIAL',
'                                    :P6_NOMBRE_COMERCIAL, ',
'                                    vcedula -- pUSUARIO',
'                                );',
'    else -- Extranjera o cualquier otro tipo',
'        ',
'        v_resultado_funcion := PKG_EMPRESA.f_insertar_empresa(',
'                                    :P6_ID_PROVINCIA, ',
'                                    :P6_NOMBRE, ',
unistr('                                    :P6_CEDULA_EXTRANJERO, -- C\00E9dula Extranjera (pCEDULA)'),
'                                    :P6_TELEFONO, ',
'                                    :P6_CORREO,',
'                                    :P6_DIRECCION_EXACTA, ',
'                                    :P6_ID_CANTON, ',
'                                    :P6_ID_DISTRITO, ',
'                                    ''FISICA'', -- pTIPO_CEDULA',
'                                    :P6_TIPO_IDENTIFICACION, -- pNACIONAL',
'                                    NULL, -- pRAZON_SOCIAL',
'                                    :P6_NOMBRE_COMERCIAL, ',
'                                    vcedula -- pUSUARIO',
'                                );',
'    end if;',
'    ',
unistr('    -- 3. PARSEO del resultado (ej: ''0|Mensaje de \00E9xito ID: 123'')'),
'    v_codigo_estado := TO_NUMBER(SUBSTR(v_resultado_funcion, 1, INSTR(v_resultado_funcion, ''|'') - 1));',
'    v_mensaje := SUBSTR(v_resultado_funcion, INSTR(v_resultado_funcion, ''|'') + 1);',
'',
unistr('    -- 4. EVALUACI\00D3N y manejo del flujo'),
'    if v_codigo_estado = 0 then',
unistr('        -- \00C9XITO: Extraer el ID (asumiendo que el mensaje de BD termina con ''ID: [N\00FAmero]'')'),
'        BEGIN',
'            v_temp_id_empresa := TO_NUMBER(TRIM(SUBSTR(v_mensaje, INSTR(v_mensaje, ''ID: '') + 4)));',
'            :P6_ID_EMPRESA := v_temp_id_empresa;',
'        EXCEPTION',
unistr('            WHEN OTHERS THEN NULL; -- No es cr\00EDtico si no se encuentra el ID en el mensaje.'),
'        END;',
'        ',
unistr('        -- Mostrar mensaje de \00E9xito'),
'        APEX_APPLICATION.G_PRINT_SUCCESS_MESSAGE := v_mensaje;',
'    else',
'        -- ERROR: Lanzar el error con el mensaje amigable devuelto por la BD',
'        -- Esto detiene el proceso y dirige el flujo al bloque EXCEPTION.',
'        RAISE_APPLICATION_ERROR(-20001, v_mensaje);',
'    end if;',
'',
'exception',
'    -- 5. MANEJO DE ERRORES CENTRALIZADO',
'    when others then',
unistr('        -- Captura el RAISE_APPLICATION_ERROR (-20001) lanzado desde la l\00F3gica de la BD.'),
'        if SQLCODE = -20001 then',
'             APEX_ERROR.ADD_ERROR(',
'                p_message          => ''Error de Base de Datos: '' || SQLERRM, -- Elimina el prefijo ''ORA-20001: ''',
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'        else',
unistr('            -- Captura cualquier otro error t\00E9cnico que no fue manejado por la BD (ej. fallas de sesi\00F3n, sintaxis)'),
'            APEX_ERROR.ADD_ERROR(',
unistr('                p_message          => ''Error de aplicaci\00F3n inesperado: '' || SQLERRM,'),
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'        end if;',
'        ',
'end;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(247993547345937620)
);
