wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(269747812688739156)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_INSERTAR_CONTRATO'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    vcedula             VARCHAR2(30);',
'    v_resultado_funcion VARCHAR2(4000); -- Captura el VARCHAR2: ''CODIGO|MENSAJE''',
'    v_codigo_estado     NUMBER;',
'    v_mensaje           VARCHAR2(4000);',
'    v_temp_id_contrato  NUMBER;         -- Almacena el ID parseado si fue exitoso',
'',
'BEGIN',
'    ',
unistr('    -- 1. Obtener la c\00E9dula del usuario'),
unistr('    -- Si falla (NO_DATA_FOUND), la excepci\00F3n ser\00E1 capturada al final.'),
'    vcedula := PKG_USUARIOS.f_consulta_usuario(:APP_USER);',
'    ',
unistr('    -- 2. Ejecutar la inserci\00F3n del contrato (Capturando el resultado completo)'),
unistr('    -- 2. Ejecutar la inserci\00F3n del contrato (Capturando el resultado completo)'),
'    v_resultado_funcion := PKG_CONTRATO.f_insertar_contrato(',
'        pID_DECLARATORIA => :P7_ID_DECLARATORIA,',
'        pID_USUARIO      => vcedula',
'    );',
'    ',
'    -- 3. PARSEO del resultado',
'    v_codigo_estado := TO_NUMBER(SUBSTR(v_resultado_funcion, 1, INSTR(v_resultado_funcion, ''|'') - 1));',
'    v_mensaje := SUBSTR(v_resultado_funcion, INSTR(v_resultado_funcion, ''|'') + 1);',
'',
unistr('    -- 4. EVALUACI\00D3N del estado'),
'    IF v_codigo_estado = 0 THEN',
unistr('        -- \00C9XITO: Extraer el ID, asignar el \00EDtem de APEX y mostrar mensaje'),
'        BEGIN',
unistr('            -- Se asume el formato de la BD: ''... ID: [N\00FAmero]'''),
'            v_temp_id_contrato := TO_NUMBER(TRIM(SUBSTR(v_mensaje, INSTR(v_mensaje, ''ID: '') + 4)));',
'            :P7_ID_CONTRATO := v_temp_id_contrato;',
'        EXCEPTION',
'            WHEN OTHERS THEN ',
unistr('                NULL; -- Si falla el parseo, no es un error cr\00EDtico.'),
'        END;',
'        ',
unistr('        -- Mostrar mensaje de \00E9xito (proveniente de la BD)'),
'        APEX_APPLICATION.G_PRINT_SUCCESS_MESSAGE := v_mensaje;',
'    ELSE',
unistr('        -- ERROR: Lanzar excepci\00F3n con el mensaje amigable de la BD (C\00F3digos -1 o -99)'),
'        RAISE_APPLICATION_ERROR(-20001, v_mensaje);',
'    END IF;',
'',
'EXCEPTION',
'    -- 5. Captura de Errores',
'    WHEN OTHERS THEN',
'        ',
'        IF SQLCODE = -20001 THEN',
unistr('             -- Captura el mensaje amigable de la funci\00F3n de contrato'),
'             APEX_ERROR.ADD_ERROR(',
'                p_message          => ''Error de Base de Datos: '' || SQLERRM, ',
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'        ELSIF SQLCODE = -1403 THEN ',
unistr('             -- Error de la funci\00F3n de usuario (NO DATA FOUND)'),
'             APEX_ERROR.ADD_ERROR(',
unistr('                p_message          => ''\26A0\FE0F Error de Usuario: No se pudo obtener la c\00E9dula del usuario logueado.'','),
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'        ELSE',
unistr('            -- Captura cualquier error t\00E9cnico inesperado de APEX/PLSQL'),
'            APEX_ERROR.ADD_ERROR(',
unistr('                p_message          => ''\274C Error T\00E9cnico Inesperado: Fall\00F3 la ejecuci\00F3n. Detalles: '' || SQLERRM,'),
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'        END IF;',
'        ',
'END;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(269732156152660287)
);
end;
