wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(173487648376460606)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_ENVIAR_MSJ'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    l_adjunto_content BLOB;',
'    l_adjunto_filename VARCHAR2(4000); -- Aumentado a 4000 para nombres largos',
'    l_adjunto_mime_type VARCHAR2(255);',
'    vMensaje_Retorno VARCHAR2(355);',
'    vRetorno boolean;',
'    vEstado NUMBER:= 8;',
'    vcorreo_destino VARCHAR2(60);',
'    vCuerpoCorreo VARCHAR2(3500);',
'    vid_secuencia NUMBER;',
'    vUser VARCHAR2(255);',
'    ',
unistr('    -- L\00EDmite de caracteres impuesto para el nombre del archivo'),
'    c_limite_nombre CONSTANT NUMBER := 500; ',
'    ',
'    -- Variables para manejo de errores en APEX',
'    v_error_msg VARCHAR2(4000);',
'    v_error_code NUMBER;',
'',
'',
'BEGIN',
'    vUser := PKG_USUARIOS.f_consulta_usuario(:APP_USER);',
'    vcorreo_destino := PKG_USUARIOS.f_consulta_correo(:P10_ID_ANALISTA);',
'    ',
unistr('    -- 1. RECUPERACI\00D3N DE ARCHIVO TEMPORAL (APEX_APPLICATION_TEMP_FILES)'),
'    SELECT ',
'        BLOB_CONTENT, ',
'        MIME_TYPE, ',
'        FILENAME ',
'    INTO ',
'        l_adjunto_content, ',
'        l_adjunto_mime_type, ',
'        l_adjunto_filename ',
'    FROM APEX_APPLICATION_TEMP_FILES ',
'    WHERE ',
'        NAME = :P10_NOTA;',
'            ',
'    -- **************************************************************',
unistr('    -- 1.5. VALIDACI\00D3N DE LONGITUD DEL NOMBRE DEL ARCHIVO'),
'    -- **************************************************************',
'    IF LENGTH(l_adjunto_filename) > c_limite_nombre THEN',
unistr('        v_error_msg := ''El nombre del archivo "'' || l_adjunto_filename || ''" excede el l\00EDmite de '' || c_limite_nombre || '' caracteres. Por favor, ac\00F3rtelo.'';'),
'        ',
'        -- Mostrar el error amigable en APEX',
'        APEX_ERROR.ADD_ERROR (',
'            p_message          => v_error_msg,',
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
unistr('        -- Detener el proceso con un c\00F3digo de error espec\00EDfico'),
'        RAISE_APPLICATION_ERROR(-20002, ''Proceso detenido: Nombre de archivo demasiado largo.'');',
'    END IF;',
'    ',
unistr('    -- 2. INSERCI\00D3N Y ACTUALIZACI\00D3N'),
'    vid_secuencia := SEQ_ID_ANOTACIONES.nextval;',
'    ',
'    PKG_DECLARATORIA.sp_insertar_anotacion(TO_CHAR(vid_secuencia), ',
'                                            l_adjunto_content, ',
'                                            l_adjunto_mime_type, ',
'                                            l_adjunto_filename, ',
'                                            vUser, ',
'                                            :P10_ID_DECLARATORIA, ',
'                                            NULL, ',
'                                            vcorreo_destino, ',
'                                            ''PUBLICO'', ',
'                                            vMensaje_Retorno, ',
'                                            vRetorno);',
'                                            ',
'    PKG_DECLARATORIA.sp_actualizar_estado(:P10_ID_DECLARATORIA, vEstado);',
'    ',
unistr('    -- 3. ENV\00CDO DE CORREO'),
'    PKG_CORREOS.sp_enviar_correo_html_adj(',
'                    p_destinatario_in => vcorreo_destino,',
'                    p_cc_in => NULL,',
'                    p_id_mensaje => 1,',
'                    p_parametros => ''NOMBRE_EMPRESA='' || :P10_NOMBRE_COMERCIAL || ',
'                                    '',ID_DECLARATORIA='' || :P10_ID_DECLARATORIA ||',
'                                    '',MENSAJE='' || :P10_CUERPO_CORREO,',
'                    p_num_oficio =>  TO_CHAR(vid_secuencia)',
'    );',
'    ',
'EXCEPTION',
unistr('    -- Excepci\00F3n si el archivo temporal no existe'),
'    WHEN NO_DATA_FOUND THEN',
unistr('        v_error_msg := ''Error: No se encontr\00F3 el archivo temporal para :P10_NOTA. Aseg\00FArese de que el archivo fue cargado correctamente.'';'),
'        APEX_ERROR.ADD_ERROR (',
'            p_message          => v_error_msg,',
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
'        RAISE_APPLICATION_ERROR(-20999, ''Proceso detenido: Archivo no encontrado.'');',
'        ',
unistr('    -- Manejo de errores generales (incluye la validaci\00F3n de 500 caracteres, -20002)'),
'    WHEN OTHERS THEN',
'        v_error_code := SQLCODE;',
'        v_error_msg := SQLERRM;',
'',
'        IF v_error_code = -20002 THEN',
unistr('            -- Captura el error de validaci\00F3n de longitud'),
unistr('            v_error_msg := ''Validaci\00F3n: '' || SUBSTR(v_error_msg, INSTR(v_error_msg, '':'') + 1);'),
'        ELSIF v_error_code <= -20000 THEN',
'            -- Captura cualquier otro RAISE_APPLICATION_ERROR',
unistr('            v_error_msg := ''Error de Aplicaci\00F3n: '' || SUBSTR(v_error_msg, INSTR(v_error_msg, '':'') + 1);'),
'        ELSE',
unistr('            -- Otros errores (conexi\00F3n, fallos de PL/SQL, etc.)'),
'            v_error_msg := ''Error inesperado en el proceso: '' || v_error_msg;',
'        END IF;',
'',
'        -- Usar APEX_ERROR para mostrar el mensaje personalizado en pantalla.',
'        APEX_ERROR.ADD_ERROR (',
'            p_message          => v_error_msg,',
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
'        ',
unistr('        -- Lanzar una excepci\00F3n de aplicaci\00F3n gen\00E9rica para DETENER el proceso.'),
unistr('        RAISE_APPLICATION_ERROR(-20999, ''Proceso detenido debido a un error de ejecuci\00F3n.'');'),
'',
'END;'))
,p_process_error_message=>'Error, al procesar la solicitud'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(173173219873417667)
,p_process_success_message=>unistr('Mensaje enviado con \00E9xito')
);
