,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    ID_TIPO_REQUISITO, ',
'    DESCRIPCION,',
'    PKG_CONTRATO.f_si_existe_archi_req_ct (ID_TIPO_REQUISITO, :P11_ID_CONTRATO) EXISTE_ARCHIVO,',
'    case PKG_CONTRATO.f_si_existe_archi_req_ct (ID_TIPO_REQUISITO, :P11_ID_CONTRATO)',
'         when ''S'' then ''far fa-check-circle''',
'         when ''N'' then ''fas fa-times-circle''',
'     end as icon_class,       ',
'     case PKG_CONTRATO.f_si_existe_archi_req_ct (ID_TIPO_REQUISITO, :P11_ID_CONTRATO)',
'         when ''S'' then ''#7AFF33''',
'         when ''N'' then ''#FF5733''',
'     end as color_class,',
'     case PKG_CONTRATO.f_si_existe_archi_req_ct (ID_TIPO_REQUISITO, :P11_ID_CONTRATO)',
'         when ''N'' then ',
'         ''javascript:$s("P11_ID_TIPO_REQUISITO",''|| ID_TIPO_REQUISITO ||'');javascript:openModal("MODAL"); $("#MODAL").trigger("apexrefresh");''',
'         when ''S'' then ''#''',
'     end as link',
'FROM TIPO_REQUISITOS',
'WHERE tipo_gestion = ''CT'' AND tipo_requisito = ''TECNICO-ECONOMICO'';'))
,p_ajax_enabled=>'Y'
,p_query_row_template=>wwv_flow_api.id(24190418485830129)
,p_query_num_rows=>15
,p_query_options=>'DERIVED_REPORT_COLUMNS'
,p_query_no_data_found=>'No tiene requistos asociados'
,p_csv_output=>'N'
