wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(269780826081402628)
,p_process_sequence=>10
,p_process_point=>'ON_SUBMIT_BEFORE_COMPUTATION'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_ADJUNTAR_ARCHIVO_REQUISITO'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_resultado_funcion VARCHAR2(4000); -- Captura el VARCHAR2: ''CODIGO|MENSAJE''',
'    v_codigo_estado     NUMBER;',
'    v_mensaje           VARCHAR2(4000);',
'    vArchivo            BLOB;',
'    vMimetype           VARCHAR2(255);',
'    vFilename           VARCHAR2(255);',
'    ',
'BEGIN',
'    ',
unistr('    -- ... (L\00F3gica para obtener el archivo de APEX_APPLICATION_TEMP_FILES) ...'),
'    IF :P11_ARCHIVO IS NULL THEN',
'        RAISE NO_DATA_FOUND; ',
'    END IF;',
'',
'    BEGIN',
'        SELECT BLOB_CONTENT, MIME_TYPE, FILENAME ',
'        INTO vArchivo, vMimetype, vFilename ',
'        FROM APEX_APPLICATION_TEMP_FILES ',
'        WHERE NAME = :P11_ARCHIVO;',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
'            RAISE;',
'    END;',
'    ',
unistr('    -- 1. Llamada a la Funci\00F3n (centralizada)'),
'    v_resultado_funcion := PKG_CONTRATO.f_insertar_archivo_req_ct (',
'        pid_contrato       => :P11_ID_CONTRATO,',
'        pid_tipo_requisito => :P11_ID_TIPO_REQUISITO,',
'        parchivo           => vArchivo,',
'        nombre_archivo     => vFilename, ',
'        pmimetype          => vMimetype,',
'        pusuario           => :APP_USER',
'    );',
'    ',
unistr('    -- 2. PARSEO y EVALUACI\00D3N'),
'    v_codigo_estado := TO_NUMBER(SUBSTR(v_resultado_funcion, 1, INSTR(v_resultado_funcion, ''|'') - 1));',
'    v_mensaje := SUBSTR(v_resultado_funcion, INSTR(v_resultado_funcion, ''|'') + 1);',
'',
'    IF v_codigo_estado = 0 THEN',
'        APEX_APPLICATION.G_PRINT_SUCCESS_MESSAGE := v_mensaje;',
'    ELSE',
'        -- Lanza el mensaje de error amigable devuelto por la BD',
'        RAISE_APPLICATION_ERROR(-20001, v_mensaje);',
'    END IF;',
'',
'EXCEPTION',
'    -- 3. Captura de Errores (Solo Errores de APEX y el -20001)',
'    WHEN NO_DATA_FOUND THEN',
'        APEX_ERROR.ADD_ERROR(',
unistr('            p_message          => ''\D83D\DD34 Error de Archivo: El campo de archivo est\00E1 vac\00EDo o el archivo subido expir\00F3. Seleccione un archivo.'','),
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
'    ',
'    WHEN OTHERS THEN',
'        IF SQLCODE = -20001 THEN',
unistr('             -- Captura el mensaje amigable de la funci\00F3n (integridad, not null, t\00E9cnico)'),
'             APEX_ERROR.ADD_ERROR(',
'                p_message          => ''Error de Base de Datos: '' || SQLERRM, ',
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'        ELSE',
unistr('            -- Captura cualquier otro error (ej. ORA-06502 por datos inv\00E1lidos)'),
'            APEX_ERROR.ADD_ERROR(',
unistr('                p_message          => ''\274C Error de Ejecuci\00F3n: Fall\00F3 la operaci\00F3n. Detalles: '' || SQLERRM,'),
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'        END IF;',
'END;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(269773173081392962)
);
end;
