wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(266520081457973848)
,p_process_sequence=>10
,p_process_point=>'ON_SUBMIT_BEFORE_COMPUTATION'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_INSERTAR_DT'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    vUser               VARCHAR2(255);',
'    v_resultado_funcion VARCHAR2(4000); -- Recibe el ''CODIGO|MENSAJE''',
'    v_codigo_estado     NUMBER;',
'    v_mensaje           VARCHAR2(4000);',
'    v_id_declaratoria   NUMBER; ',
'',
'begin',
'',
'    vUser := PKG_USUARIOS.f_consulta_usuario(:APP_USER);',
'',
'    if :P13_TIPO_OPERA_DT is not null AND :P13_ID_TIPODT is not null then',
'        ',
unistr('        -- 1. EJECUCI\00D3N: Llamada a la funci\00F3n (sin par\00E1metros IN OUT)'),
'        if :P13_ID_CATEGORIA is not null then',
'            v_resultado_funcion := PKG_DECLARATORIA.f_insertar_declaratoria(',
'                                        vUser, :P13_ID_EMPRESA, :P13_TIPO_OPERA_DT, :P13_ID_TIPODT, :P13_ID_CATEGORIA',
'                                    );',
'        else',
'            v_resultado_funcion := PKG_DECLARATORIA.f_insertar_declaratoria(',
'                                        vUser, :P13_ID_EMPRESA, :P13_TIPO_OPERA_DT, :P13_ID_TIPODT, NULL',
'                                    );',
'        end if;',
'        ',
'        -- 2. PARSEO del resultado',
'        v_codigo_estado := TO_NUMBER(SUBSTR(v_resultado_funcion, 1, INSTR(v_resultado_funcion, ''|'') - 1));',
'        v_mensaje := SUBSTR(v_resultado_funcion, INSTR(v_resultado_funcion, ''|'') + 1);',
'',
unistr('        -- 3. EVALUACI\00D3N y manejo del flujo'),
'        if v_codigo_estado = 0 then',
unistr('            -- \00C9XITO: Asignar ID y mostrar mensaje de \00E9xito'),
'            BEGIN',
'                v_id_declaratoria := TO_NUMBER(TRIM(SUBSTR(v_mensaje, INSTR(v_mensaje, ''ID: '') + 4)));',
'                :P13_ID_DECLARATORIA := v_id_declaratoria;',
'            EXCEPTION',
'                WHEN OTHERS THEN NULL; ',
'            END;',
'',
'            apex_application.g_print_success_message := v_mensaje;',
'        else',
unistr('            -- ERROR: Lanzar excepci\00F3n controlada con el mensaje de la BD'),
'            RAISE_APPLICATION_ERROR(-20001, v_mensaje);',
'        end if;',
'        ',
'    end if;',
'',
'exception',
'    -- 4. MANEJO DE ERRORES (Solo captura el RAISE_APPLICATION_ERROR -20001)',
'    when others then',
'        if SQLCODE = -20001 then',
'             apex_error.add_error(',
'                p_message          => ''Error de Base de Datos: '' || SQLERRM, -- Muestra el mensaje de la BD',
'                p_display_location => apex_error.c_inline_in_notification',
'            );',
'        else',
unistr('            -- Error t\00E9cnico gen\00E9rico de APEX'),
'            apex_error.add_error(',
unistr('                p_message          => ''Error de aplicaci\00F3n. Consulte al t\00E9cnico: '' || SQLERRM,'),
'                p_display_location => apex_error.c_inline_in_notification',
'            );',
'        end if;',
'end;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(247997052941937623)
);
end;
