,p_component_template_options=>'#DEFAULT#:t-Report--stretch:t-Report--altRowsDefault:t-Report--rowHighlight'
,p_display_point=>'BODY'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    tr.ID_TIPO_REQUISITO, ',
'    tr.DESCRIPCION,',
'    PKG_DECLARATORIA.f_si_existe_archi_req_dt (tr.ID_TIPO_REQUISITO, :P14_ID_DECLARATORIA) EXISTE_ARCHIVO,',
'    case PKG_DECLARATORIA.f_si_existe_archi_req_dt (tr.ID_TIPO_REQUISITO, :P14_ID_DECLARATORIA)',
'         when ''S'' then ''far fa-check-circle''',
'         when ''N'' then ''fas fa-times-circle''',
'     end as icon_class,       ',
'     case PKG_DECLARATORIA.f_si_existe_archi_req_dt (tr.ID_TIPO_REQUISITO, :P14_ID_DECLARATORIA)',
'         when ''S'' then ''#7AFF33''',
'         when ''N'' then ''#FF5733''',
'     end as color_class,',
'     case PKG_DECLARATORIA.f_si_existe_archi_req_dt (tr.ID_TIPO_REQUISITO, :P14_ID_DECLARATORIA)',
'         when ''N'' then ',
'         ''javascript:$s("P14_ID_TIPO_REQUISITO",''|| tr.ID_TIPO_REQUISITO ||'');javascript:openModal("ID"); $("#ID").trigger("apexrefresh");''',
'         when ''S'' then ''#''',
