,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'BEGIN',
'    :P14_REQ_COMPLETOS := PKG_DECLARATORIA.f_validar_req_completos (:P14_ID_TIPODT, :P14_ID_DECLARATORIA);',
