wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(248698579843617319)
,p_process_sequence=>120
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_FINALIZAR'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'    -- 1. PRIMER UPDATE (DECLARATORIA_TURISTICA)',
'    UPDATE DECLARATORIA_TURISTICA',
'    SET ',
'        ESTADODT = 1,',
'        CANTIDAD_COLABORADORES = :P14_CANTIDAD_COLABORADORES,',
'        MONTO_INVERSION = :P14_MONTO_INVERSION,',
'        MONEDA = :P14_MONEDA',
'    WHERE ID_DECLARATORIA = :P14_ID_DECLARATORIA;',
'    ',
'    -- 2. SEGUNDO UPDATE (A OTRA TABLA)',
'    UPDATE EMPRESA',
'    SET',
'        ESTADO = ''AC''',
'    WHERE ID_EMPRESA = :P14_ID_EMPRESA;',
'    ',
unistr('    -- 3. NOTIFICACI\00D3N'),
'    IF :P14_ID_DECLARATORIA IS NOT NULL THEN',
'        PKG_UTILIDADES.sp_notifica_solicitud(1, :P14_ID_DECLARATORIA);',
'    END IF;',
'    ',
'    -- 4. CONFIRMAR CAMBIOS',
'    COMMIT; -- Confirma TODAS las operaciones si no hubo errores',
'',
'EXCEPTION',
'    -- Manejo de cualquier error que ocurra en el bloque BEGIN',
'    WHEN OTHERS THEN',
'        -- 5. REVERTIR CAMBIOS (Muy importante!)',
'        ROLLBACK; ',
'        ',
'        -- Relanzar el error para que APEX lo pueda capturar y mostrar al usuario',
unistr('        RAISE_APPLICATION_ERROR(-20001, ''Error al procesar la solicitud (c\00F3digo: '' || SQLCODE || ''): '' || SQLERRM);'),
'        ',
'END;'))
,p_process_error_message=>'Error al generar la solicitud, si el error persiste contacte al administrador del sistema.'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(248001045497937625)
,p_process_success_message=>unistr('La solicitud fue ingresada con \00E9xito')
);
