wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(266669709535470240)
,p_process_sequence=>110
,p_process_point=>'ON_SUBMIT_BEFORE_COMPUTATION'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_ADJUNTAR_ARCHIVO_REQUISITO'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    vArchivo            BLOB;',
'    vMimetype           VARCHAR2(255);',
'    vFilename           VARCHAR2(255);',
'    ',
'BEGIN',
'    ',
unistr('    -- 1. Intentar obtener el archivo (L\00F3gica original de APEX)'),
'    IF :P14_ARCHIVO IS NULL THEN',
unistr('        -- Si el \00EDtem est\00E1 vac\00EDo, lo tratamos como archivo no encontrado.'),
'        RAISE NO_DATA_FOUND; ',
'    END IF;',
'',
'    -- Bloque anidado para obtener los detalles del archivo',
'    BEGIN',
'        SELECT BLOB_CONTENT, MIME_TYPE, FILENAME ',
'        INTO vArchivo, vMimetype, vFilename ',
'        FROM APEX_APPLICATION_TEMP_FILES ',
'        WHERE NAME = :P14_ARCHIVO;',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
unistr('            -- Captura si el archivo expir\00F3 o no existe en la tabla temporal'),
'            RAISE NO_DATA_FOUND; ',
'    END;',
'',
unistr('    -- 2. Llamada al Procedimiento (SIN par\00E1metros IN OUT)'),
'    PKG_DECLARATORIA.sp_insertar_archivo_req_dt (',
'        pid_declaratoria    => :P14_ID_DECLARATORIA,',
'        pid_tipo_requisito  => :P14_ID_TIPO_REQUISITO,',
'        parchivo            => vArchivo,',
'        pnombre_archivo     => vFilename,',
'        pmimetype           => vMimetype,',
'        pusuario            => :APP_USER',
'    );',
'    ',
unistr('    -- 3. Manejo de \00C9xito (Si la ejecuci\00F3n llega aqu\00ED, NO HUBO RAISE)'),
unistr('    APEX_APPLICATION.G_PRINT_SUCCESS_MESSAGE := ''\2705 Documento '' || vFilename || '' guardado exitosamente.'';'),
'    COMMIT; -- Hacemos COMMIT porque la BD no lo hizo al ser un PROCEDIMIENTO',
'    ',
'EXCEPTION',
'    -- El bloque EXCEPTION captura todos los RAISE lanzados: NO_DATA_FOUND y -20001',
'    ',
'    -- 4. Manejo de Archivo Faltante/Expirado (NO_DATA_FOUND)',
'    WHEN NO_DATA_FOUND THEN',
'        APEX_ERROR.ADD_ERROR(',
unistr('            p_message          => ''\D83D\DD34 Error de Archivo: El campo de archivo est\00E1 vac\00EDo o el archivo subido expir\00F3. Seleccione un archivo.'','),
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
unistr('        -- Un RAISE dentro de la funci\00F3n llama a ROLLBACK, pero si el error es en APEX, lo hacemos aqu\00ED.'),
'        ROLLBACK; ',
'',
'    -- 5. Manejo de Errores Controlados de la BD (-20001) y Otros Errores',
'    WHEN OTHERS THEN',
unistr('        -- Si el error viene del Procedimiento (SQLCODE = -20001), APEX mostrar\00E1 el mensaje amigable.'),
unistr('        -- Si el error es otro, mostramos un mensaje t\00E9cnico.'),
'        ',
'        IF SQLCODE = -20001 THEN',
'             APEX_ERROR.ADD_ERROR(',
'                p_message          => ''Error de Base de Datos: '' || SQLERRM,',
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'        ELSE',
'            APEX_ERROR.ADD_ERROR(',
unistr('                p_message          => ''\274C Error T\00E9cnico en APEX: Fall\00F3 la ejecuci\00F3n. Detalles: '' || SQLERRM,'),
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'        END IF;',
'',
'        ROLLBACK; ',
'END;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(266668755290470230)
);
end;
