wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(248857663125265654)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_INSERTAR_EMPRESA_JURIDICA'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    vcedula             VARCHAR2(30);',
unistr('    v_resultado_funcion VARCHAR2(4000); -- \00A1Ahora captura el VARCHAR2 de retorno!'),
'    v_codigo_estado     NUMBER;',
'    v_mensaje           VARCHAR2(4000);',
'    v_temp_id_empresa   NUMBER;         -- Variable temporal para almacenar el ID parseado',
'',
'begin',
'',
unistr('    -- 1. Identificar la c\00E9dula del usuario logueado'),
'    vcedula := PKG_USUARIOS.f_consulta_usuario(:APP_USER);',
'',
unistr('    -- 2. Ejecutar la inserci\00F3n de la empresa (capturando el resultado completo: ''0|Mensaje...'')'),
'    v_resultado_funcion := PKG_EMPRESA.f_insertar_empresa(',
'                                :P15_ID_PROVINCIA, ',
'                                :P15_NOMBRE_SOLICITANTE, -- Reemplazar NULL por el nombre real (asumo P15_NOMBRE_SOLICITANTE)',
'                                :P15_CEDULA, ',
'                                :P15_TELEFONO, ',
'                                :P15_CORREO,',
'                                :P15_DIRECCION_EXACTA, ',
'                                :P15_ID_CANTON, ',
'                                :P15_ID_DISTRITO, ',
'                                ''JURIDICA'', -- pTIPO_CEDULA',
'                                ''NACIONAL'', -- pNACIONAL (Ajustar si aplica: asumo JURIDICA es Nacional)',
'                                :P15_RAZON_SOCIAL, ',
'                                :P15_NOMBRE_COMERCIAL, ',
'                                vcedula     -- pUSUARIO',
'                            );',
'    ',
unistr('    -- 3. PARSEO del resultado (Separar c\00F3digo y mensaje)'),
'    v_codigo_estado := TO_NUMBER(SUBSTR(v_resultado_funcion, 1, INSTR(v_resultado_funcion, ''|'') - 1));',
'    v_mensaje := SUBSTR(v_resultado_funcion, INSTR(v_resultado_funcion, ''|'') + 1);',
'',
unistr('    -- 4. EVALUACI\00D3N y manejo del flujo'),
'    if v_codigo_estado = 0 then',
unistr('        -- \00C9XITO: Extraer el ID y mostrar mensaje'),
'        BEGIN',
unistr('            -- Se asume que el mensaje de \00E9xito en la BD es ''... ID: [N\00FAmero]'''),
'            v_temp_id_empresa := TO_NUMBER(TRIM(SUBSTR(v_mensaje, INSTR(v_mensaje, ''ID: '') + 4)));',
'            :P15_ID_EMPRESA := v_temp_id_empresa;',
'        EXCEPTION',
'            WHEN OTHERS THEN ',
unistr('                -- Si el parseo falla, el ID de APEX queda nulo, pero el mensaje de \00E9xito se muestra.'),
'                NULL; ',
'        END;',
'        ',
unistr('        -- Mostrar mensaje de \00E9xito (proveniente de la BD)'),
'        APEX_APPLICATION.G_PRINT_SUCCESS_MESSAGE := v_mensaje;',
'    else',
unistr('        -- ERROR: Lanzar una excepci\00F3n controlada con el mensaje amigable devuelto por la BD'),
'        RAISE_APPLICATION_ERROR(-20001, v_mensaje);',
'    end if;',
'',
'exception',
'    -- 5. Captura de Errores Centralizados',
unistr('    -- S\00F3lo capturamos el RAISE_APPLICATION_ERROR (-20001) y errores t\00E9cnicos no controlados.'),
'    when others then',
'        if SQLCODE = -20001 then',
unistr('             -- Muestra el mensaje amigable que viene de la funci\00F3n PL/SQL'),
'             APEX_ERROR.ADD_ERROR(',
'                p_message          => ''Error de Base de Datos: '' || SQLERRM, -- Elimina el prefijo ''ORA-20001: ''',
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'        else',
unistr('            -- Captura cualquier otro error t\00E9cnico que no fue cubierto por la BD'),
'            APEX_ERROR.ADD_ERROR(',
unistr('                p_message          => ''\274C Error de aplicaci\00F3n inesperado: '' || SQLERRM,'),
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'        end if;',
'        ',
'end;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(248711604391696778)
);
