wwv_flow_api.create_page_validation(
 p_id=>wwv_flow_api.id(315597917320018548)
,p_validation_name=>'VAL_IDENTIFICACION_NOT_EXISTS'
,p_validation_sequence=>40
,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_count NUMBER;',
'BEGIN',
unistr('    -- 1. Contar cu\00E1ntos apoderados existen con la misma IDENTIFICACION'),
'    --    y la misma ID_EMPRESA, PERO excluyendo el registro actual.',
'    SELECT COUNT(*)',
'    INTO v_count',
'    FROM APODERADO_LEGAL',
'    WHERE IDENTIFICACION = :P20_IDENTIFICACION',
'      AND ID_EMPRESA = :P20_ID_EMPRESA',
unistr('      -- ESTA ES LA CLAVE: Excluir el registro que se est\00E1 editando'),
'      AND ID_APODERADO != :P20_ID_APODERADO; ',
'',
'    -- 2. Evaluar el resultado',
'    IF v_count > 0 THEN',
'        -- Si v_count es mayor a 0, existe otro registro con el mismo ID y EMPRESA.',
unistr('        RETURN ''\00A1Error! Ya existe **otro** Apoderado Legal con la identificaci\00F3n '' || :P20_IDENTIFICACION || '' registrado para esta empresa.'';'),
'    ELSE',
unistr('        -- Si v_count es 0, significa que el n\00FAmero de identificaci\00F3n es \00FAnico'),
unistr('        -- o pertenece \00FAnicamente al registro actual que se est\00E1 modificando.'),
'        RETURN NULL;',
'    END IF;',
'',
'END;'))
,p_validation_type=>'FUNC_BODY_RETURNING_ERR_TEXT'
,p_always_execute=>'Y'
,p_validation_condition=>'BTN_CREAR, BTN_ACTUALIZAR'
,p_validation_condition_type=>'REQUEST_IN_CONDITION'
,p_associated_item=>wwv_flow_api.id(249065178913996030)
,p_error_display_location=>'INLINE_WITH_FIELD'
);
