wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(249247122848786725)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_INSERTAR_APODERADO_LEGAL'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    v_resultado_funcion VARCHAR2(4000); -- Captura el VARCHAR2: ''CODIGO|MENSAJE''',
'    v_codigo_estado     NUMBER;',
'    v_mensaje           VARCHAR2(4000);',
unistr('    v_temp_id_apoderado NUMBER;         -- Almacena el ID si la operaci\00F3n es exitosa'),
'',
'begin',
'',
unistr('    -- 1. Ejecutar la inserci\00F3n del apoderado'),
unistr('    -- NOTA: Se asume que la funci\00F3n est\00E1 dentro de un paquete llamado PKG_APODERADO'),
'    v_resultado_funcion := PKG_EMPRESA.f_insertar_apoderado(',
'                                :P20_NOMBRE_APODERADO,',
'                                :P20_TIPO_IDENTIFCACION,',
'                                :P20_IDENTIFICACION,',
'                                :P20_ID_EMPRESA',
'                            );',
'    ',
'    -- 2. PARSEO del resultado',
'    v_codigo_estado := TO_NUMBER(SUBSTR(v_resultado_funcion, 1, INSTR(v_resultado_funcion, ''|'') - 1));',
'    v_mensaje := SUBSTR(v_resultado_funcion, INSTR(v_resultado_funcion, ''|'') + 1);',
'',
unistr('    -- 3. EVALUACI\00D3N del estado'),
'    if v_codigo_estado = 0 then',
unistr('        -- \00C9XITO: Extraer el ID (opcional) y mostrar el mensaje'),
'        BEGIN',
unistr('            -- Se asume el formato de la BD: ''... ID: [N\00FAmero]'''),
'            v_temp_id_apoderado := TO_NUMBER(TRIM(SUBSTR(v_mensaje, INSTR(v_mensaje, ''ID: '') + 4)));',
unistr('            :P20_ID_APODERADO := v_temp_id_apoderado; -- Actualizar el \00EDtem con el ID generado'),
'        EXCEPTION',
'            WHEN OTHERS THEN ',
'                NULL; ',
'        END;',
'        ',
unistr('        -- Mostrar mensaje de \00E9xito (proveniente de la BD)'),
'        APEX_APPLICATION.G_PRINT_SUCCESS_MESSAGE := v_mensaje;',
'    else',
unistr('        -- ERROR: Lanzar una excepci\00F3n controlada con el mensaje amigable de la BD'),
'        RAISE_APPLICATION_ERROR(-20001, v_mensaje);',
'    end if;',
'',
'exception',
'    -- 4. Captura de Errores Centralizados',
'    when others then',
'        if SQLCODE = -20001 then',
'             -- Muestra el mensaje amigable',
'             APEX_ERROR.ADD_ERROR(',
'                p_message          => ''Error de Base de Datos: '' || SQLERRM,',
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'        else',
unistr('            -- Captura cualquier error t\00E9cnico inesperado'),
'            APEX_ERROR.ADD_ERROR(',
unistr('                p_message          => ''\274C Error de aplicaci\00F3n inesperado: '' || SQLERRM,'),
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'        end if;',
'        ',
'end;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(249065577276996034)
,p_process_when=>'P20_ID_APODERADO'
,p_process_when_type=>'ITEM_IS_NOT_NULL'
);
wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(249247251965786726)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_ACTUALIZAR_APODERADO_LEGAL'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    v_resultado_funcion VARCHAR2(4000); -- Captura el VARCHAR2: ''CODIGO|MENSAJE''',
'    v_codigo_estado     NUMBER;',
'    v_mensaje           VARCHAR2(4000);',
'',
'begin',
'',
unistr('    -- 1. Ejecutar la actualizaci\00F3n del apoderado'),
unistr('    -- NOTA: Se asume que la funci\00F3n est\00E1 dentro de un paquete llamado PKG_APODERADO'),
'    v_resultado_funcion := PKG_EMPRESA.f_actualizar_apoderado(',
'                                :P20_ID_APODERADO,',
'                                :P20_NOMBRE_APODERADO,',
'                                :P20_TIPO_IDENTIFCACION,',
'                                :P20_IDENTIFICACION',
'                            );',
'    ',
'    -- 2. PARSEO del resultado',
'    v_codigo_estado := TO_NUMBER(SUBSTR(v_resultado_funcion, 1, INSTR(v_resultado_funcion, ''|'') - 1));',
'    v_mensaje := SUBSTR(v_resultado_funcion, INSTR(v_resultado_funcion, ''|'') + 1);',
'',
unistr('    -- 3. EVALUACI\00D3N del estado'),
'    if v_codigo_estado = 0 then',
unistr('        -- \00C9XITO (C\00F3digo 0)'),
'        APEX_APPLICATION.G_PRINT_SUCCESS_MESSAGE := v_mensaje;',
'    elsif v_codigo_estado = -2 then',
unistr('        -- ADVERTENCIA (C\00F3digo -2: Fila no encontrada)'),
unistr('        -- Usamos ADD_ERROR para mostrar como advertencia sin detener la transacci\00F3n'),
'        APEX_ERROR.ADD_ERROR(',
'             p_message          => v_mensaje,',
'             p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
'    else',
unistr('        -- ERROR (C\00F3digo -1 o -99): Lanzar excepci\00F3n con mensaje amigable'),
'        RAISE_APPLICATION_ERROR(-20001, v_mensaje);',
'    end if;',
'',
'exception',
'    -- 4. Captura de Errores',
'    when others then',
'        if SQLCODE = -20001 then',
'             -- Muestra el mensaje amigable de la BD',
'             APEX_ERROR.ADD_ERROR(',
'                p_message          => ''Error de Base de Datos: '' || SQLERRM,',
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'        else',
unistr('            -- Captura cualquier error t\00E9cnico inesperado de APEX/PLSQL'),
'            APEX_ERROR.ADD_ERROR(',
unistr('                p_message          => ''\274C Error de aplicaci\00F3n inesperado: '' || SQLERRM,'),
'                p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'            );',
'        end if;',
'        ',
'end;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(249247028162786724)
,p_process_when=>'P20_ID_APODERADO'
,p_process_when_type=>'ITEM_IS_NOT_NULL'
);
wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(249300329847525927)
,p_process_sequence=>30
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_ELIMINAR_APODERADO_LEGAL'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
