,p_process_sequence=>10
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_DATOS_USUARIO'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    vnombre VARCHAR2(30);',
'    vpapellido VARCHAR2(30);',
'    vsapellido VARCHAR2(30);',
'    vtipocedula VARCHAR2(20);',
'    vcorreo VARCHAR2(60);',
'    vtelefono VARCHAR2(60);   ',
'    ',
'    cursor c_datosUsuario is',
'        SELECT ',
'            NOMBRE, ',
'            PAPELLIDO, ',
'            SAPELLIDO, ',
'            TIPO_CEDULA, ',
'            CORREO, ',
'            TELEFONO ',
'       from ',
'           USUARIOS_GESTION ',
'       where ',
'           CEDULA = :APP_USER;',
'begin',
'    open c_datosUsuario;',
'    fetch c_datosUsuario into vnombre, vpapellido, vsapellido, vtipocedula, vcorreo, vtelefono;',
'    close c_datosUsuario;',
'   ',
'   :P23_NOMBRE := vnombre;',
'   :P23_PAPELLIDO := vpapellido;',
'   :P23_SAPELLIDO := vsapellido;',
'   :P23_TIPO_CEDULA := vtipocedula;',
'   :P23_CEDULA := :APP_USER;',
'   :P23_CORREO := vcorreo;',
'   :P23_TELEFONO := vtelefono;',
'   ',
'end;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
);
wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(317300744876438869)
,p_process_sequence=>20
